#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>

using namespace std;

/**
 * @brief Solves the minimum XOR path problem in a grid.
 * 
 * The problem can be solved using a meet-in-the-middle approach due to the constraint m*n <= 1000.
 * All paths from (0, 0) to (m-1, n-1) have a total length of (m-1) + (n-1) + 1 = m + n - 1.
 * The middle step occurs around the diagonal where the number of steps taken from (0, 0) is approximately 
 * half the total number of steps.
 * 
 * Total steps = m + n - 2. Midpoint steps = floor((m+n-2)/2).
 * The path length (number of cells) at the middle is mid_len = floor((m+n-1)/2).
 * 
 * We use BFS/DFS to find all possible XOR sums at cells reached after exactly k steps, 
 * where k is roughly half the path length.
 * 
 * State: (row, col, xor_sum)
 */
class Solution {
public:
    int64_t solve(vector<vector<int64_t>>& grid) {
        int m = grid.size();
        int n = grid[0].size();

        if (m == 1 && n == 1) {
            return grid[0][0];
        }

        // Total steps required = m + n - 2.
        // We aim to meet roughly halfway. The number of cells in the path is L = m + n - 1.
        // The middle cell(s) will be reached after roughly L/2 steps (or L/2 - 1 moves).
        // Let's target paths of length K = ceil((m + n - 1) / 2).
        int target_len = (m + n) / 2; 

        // Map: target_len -> set of (row, col) -> set of XOR sums
        // Since we might reach the same (r, c) with different XOR sums at the same step count,
        // we store the set of achievable XOR sums for each cell at that step count.
        // Step count 'k' is the number of cells visited, starting from k=1 for (0, 0).
        vector<vector<vector<int64_t>>> xor_sums_at_step(m, vector<vector<int64_t>>(n));

        // Queue for BFS: {row, col, current_xor_sum, current_length}
        // We only need to store (row, col, xor_sum) and rely on the BFS level for length, 
        // but explicitly tracking length or using layers is safer for meet-in-the-middle.

        // BFS state: {r, c, current_xor}
        queue<tuple<int, int, int64_t>> q;

        // Start at (0, 0)
        int64_t start_xor = grid[0][0];
        q.push({0, 0, start_xor});

        // Initialize the starting point in our tracking structure
        xor_sums_at_step[0][0].push_back(start_xor);

        int current_len = 1;

        // We iterate layer by layer (by path length)
        while (!q.empty()) {
            int level_size = q.size();
            current_len++; // The next layer will have length 'current_len'

            // If we have passed the target meeting point, we might stop early if we were only looking for one point,
            // but since we need ALL paths, we continue until the queue is empty or we reach the end.
            // However, for MITM, we stop when current_len > target_len.
            if (current_len > m + n - 1) break;

            queue<tuple<int, int, int64_t>> next_q;

            while (level_size-- > 0) {
                auto [r, c, current_xor] = q.front();
                q.pop();

                // Move right (r, c+1)
                if (c + 1 < n) {
                    int next_r = r;
                    int next_c = c + 1;
                    int64_t next_xor = current_xor ^ grid[next_r][next_c];

                    // Store the result for the next step length
                    xor_sums_at_step[next_r][next_c].push_back(next_xor);
                    next_q.push({next_r, next_c, next_xor});
                }

                // Move down (r+1, c)
                if (r + 1 < m) {
                    int next_r = r + 1;
                    int next_c = c;
                    int64_t next_xor = current_xor ^ grid[next_r][next_c];

                    // Store the result for the next step length
                    xor_sums_at_step[next_r][next_c].push_back(next_xor);
                    next_q.push({next_r, next_c, next_xor});
                }
            }

            // Move to the next level
            q = next_q;
        }

        // --- Meet in the Middle Logic ---

        // The actual meeting point is when the path length is ceil((m+n-1)/2).
        // If m+n-1 is odd, there is one middle cell.
        // If m+n-1 is even, there are two middle cells (one reached by moving right/down from the previous layer).

        // Since we stored *all* paths up to the final cell (m-1, n-1), the standard MITM
        // technique where we only store paths up to half the length is not strictly necessary 
        // if m*n is small enough that standard DP or full BFS/DFS works.

        // Given m*n <= 1000, a simple DP or full path enumeration might be too slow if the grid is 1000x1.
        // However, the number of paths is C(m+n-2, m-1), which can be large (e.g., C(998, 499)).
        // The MITM approach is necessary.

        // Let K be the length of the paths we store in the first half.
        int K = (m + n) / 2; // Target length (number of cells)

        // We need to collect all XOR sums achievable at cells (r, c) such that r + c = K - 1 (i.e., path length K).
        // We must ensure our BFS correctly populates xor_sums_at_step up to the required depth K.

        // Re-running the BFS structure to isolate the middle layer is cleaner for MITM.

        // Resetting for a clean MITM approach focused on the middle layer.

        // Map: (r, c) -> Set of XOR sums achievable at this point after K-1 moves (K cells visited)
        vector<vector<vector<int64_t>>> first_half_sums(m, vector<vector<int64_t>>(n));

        queue<tuple<int, int, int64_t>> q_start;
        q_start.push({0, 0, grid[0][0]});
        first_half_sums[0][0].push_back(grid[0][0]);

        int current_steps = 0; // Number of moves made from (0, 0)

        while (!q_start.empty() && current_steps < m + n - 2) {
            int level_size = q_start.size();
            current_steps++;

            queue<tuple<int, int, int64_t>> next_q;

            while (level_size-- > 0) {
                auto [r, c, current_xor] = q_start.front();
                q_start.pop();

                // If we reached the middle step count (m+n-2)/2 moves, we store these sums 
                // and stop expanding from them in the first half.
                if (current_steps == (m + n - 2) / 2 && (m + n - 2) % 2 == 0) {
                    // This cell is on the meeting line for even total steps
                    continue; 
                }

                // Move right
                if (c + 1 < n) {
                    int next_r = r;
                    int next_c = c + 1;
                    int64_t next_xor = current_xor ^ grid[next_r][next_c];

                    first_half_sums[next_r][next_c].push_back(next_xor);
                    next_q.push({next_r, next_c, next_xor});
                }

                // Move down
                if (r + 1 < m) {
                    int next_r = r + 1;
                    int next_c = c;
                    int64_t next_xor = current_xor ^ grid[next_r][next_c];

                    first_half_sums[next_r][next_c].push_back(next_xor);
                    next_q.push({next_r, next_c, next_xor});
                }
            }
            q_start = next_q;
        }

        // If m+n-1 is odd, the middle layer is the final layer of the first half BFS.
        // If m+n-1 is even, the meeting point is between two layers.

        // Let's simplify: if m*n <= 1000, the number of paths might still be too large for explicit storage if they are all distinct.
        // However, the number of reachable states (r, c) is M*N <= 1000. 
        // The number of paths to a specific cell (r, c) is C(r+c, r). If r+c is around 500, this is too many.
        // The XOR sums are bounded by 2^10 = 1024. This suggests Dynamic Programming based on XOR values.

        // DP State: dp[r][c] = set of all possible XOR sums reaching (r, c).
        // Since the maximum XOR value is 1023, we can use a boolean array or a bitset/vector of size 1024.

        const int MAX_XOR = 1024;
        // dp[r][c] stores a bitmask where the j-th bit is set if XOR sum j is reachable at (r, c).
        vector<vector<int>> dp(m, vector<int>(n, 0));

        // Base case
        dp[0][0] = (1 << grid[0][0]);

        for (int r = 0; r < m; ++r) {
            for (int c = 0; c < n; ++c) {
                if (r == 0 && c == 0) continue;

                int current_mask = 0;

                // From top (r-1, c)
                if (r > 0) {
                    int top_mask = dp[r-1][c];
                    int contribution = 0;
                    // Iterate through all reachable XOR sums j from (r-1, c)
                    for (int j = 0; j < MAX_XOR; ++j) {
                        if ((top_mask >> j) & 1) {
                            // If j is reachable, then j ^ grid[r][c] is reachable at (r, c)
                            contribution |= (1 << (j ^ grid[r][c]));
                        }
                    }
                    current_mask |= contribution;
                }

                // From left (r, c-1)
                if (c > 0) {
                    int left_mask = dp[r][c-1];
                    int contribution = 0;
                    // Iterate through all reachable XOR sums j from (r, c-1)
                    for (int j = 0; j < MAX_XOR; ++j) {
                        if ((left_mask >> j) & 1) {
                            // If j is reachable, then j ^ grid[r][c] is reachable at (r, c)
                            contribution |= (1 << (j ^ grid[r][c]));
                        }
                    }
                    current_mask |= contribution;
                }

                dp[r][c] = current_mask;
            }
        }

        // The result is the minimum set bit in dp[m-1][n-1]
        int final_mask = dp[m-1][n-1];
        int min_xor = MAX_XOR - 1; // Initialize to maximum possible XOR (1023)

        for (int x = 0; x < MAX_XOR; ++x) {
            if ((final_mask >> x) & 1) {
                min_xor = min(min_xor, x);
            }
        }

        return min_xor;
    }
};
